import java.io.*;
import okhttp3.*;
public class IoTDeviceClient {
    private static final String CLOUD_API = "https://your-cloud-api/"; // replace with your cloud API URL here 
    
    public void sendDeviceData(String deviceId, Map<String, Object> data) throws IOException{
        OkHttpClient client = new OkHttpClient();
        
        String urlStr =  CLOUD_API + "/devices/"+deviceId; // construct the API URL for sending to cloud 
    
       RequestBody requestBody=new FormBody.Builder()  
                .add("data", data)   
               .build();     
         
         client.newRequest().url(urlStr).post(requestBody);// send HTTP POST with JSON body in the form of Map<String, Object> to cloud API 
     }       
}